export const findHtmlPptBeautifulTemplateDeck = (
  slug?: string | null
): HtmlPptBeautifulTemplateDeck | null => {
  if (!slug) return null;
  return (HTML_PPT_BEAUTIFUL_TEMPLATE_DECKS as Record<string, HtmlPptBeautifulTemplateDeck>)[slug] || null;
};

export const getHtmlPptBeautifulTemplateDeck = (
  slug?: string | null
): HtmlPptBeautifulTemplateDeck =>
  findHtmlPptBeautifulTemplateDeck(slug) || HTML_PPT_BEAUTIFUL_TEMPLATE_DECKS["8-bit-orbit"];
